def _get_tzinfo(tz_expr: Optional[TZ_EXPR]) -> dt_tzinfo:
    """Get normalized tzinfo object from various inputs."""
    if tz_expr is None:
        return timezone.utc
    if isinstance(tz_expr, dt_tzinfo):
        return tz_expr
    else:
        try:
            return parser.TzinfoParser.parse(tz_expr)
        except parser.ParserError:
            raise ValueError(f"{tz_expr!r} not recognized as a timezone.")

def parse(cls, tzinfo_string: str) -> dt_tzinfo:
    """
    Parse a timezone string and return a datetime timezone object.

    :param tzinfo_string: The timezone string to parse.
    :type tzinfo_string: str
    :returns: The parsed datetime timezone object.
    :rtype: datetime.timezone
    :raises ParserError: If the timezone string cannot be parsed.
    """
    tzinfo: Optional[dt_tzinfo] = None

    if tzinfo_string == "local":
        tzinfo = datetime.now().astimezone().tzinfo

    elif tzinfo_string in ["utc", "UTC", "Z"]:
        tzinfo = timezone.utc

    else:
        iso_match = cls._TZINFO_RE.match(tzinfo_string)

        if iso_match:
            sign: Optional[str]
            hours: str
            minutes: Union[str, int, None]
            sign, hours, minutes = iso_match.groups()
            seconds = int(hours) * 3600 + int(minutes or 0) * 60

            if sign == "-":
                seconds *= -1

            tzinfo = timezone(timedelta(seconds=seconds))

        else:
            try:
                tzinfo = ZoneInfo(tzinfo_string)
            except ZoneInfoNotFoundError:
                tzinfo = None

    if tzinfo is None:
        raise ParserError(f"Could not parse timezone expression {tzinfo_string!r}.")

    return tzinfo

def _format_timeframe(self, timeframe: TimeFrameLiteral, delta: int) -> str:
    """Slovak aware time frame format function, takes into account
    the differences between past and future forms."""
    abs_delta = abs(delta)
    form = self.timeframes[timeframe]

    if isinstance(form, str):
        return form.format(abs_delta)

    if delta == 0:
        key = "zero"  # And *never* use 0 in the singular!
    elif delta < 0:
        key = "past"
    else:
        if "future-singular" not in form:
            key = "future"
        elif 2 <= abs_delta % 10 <= 4 and (
            abs_delta % 100 < 10 or abs_delta % 100 >= 20
        ):
            key = "future-singular"
        else:
            key = "future-paucal"

    form: str = form[key]
    return form.format(abs_delta)

def sliced(seq, n, strict=False):
    """Yield slices of length *n* from the sequence *seq*.

    >>> list(sliced((1, 2, 3, 4, 5, 6), 3))
    [(1, 2, 3), (4, 5, 6)]

    By the default, the last yielded slice will have fewer than *n* elements
    if the length of *seq* is not divisible by *n*:

    >>> list(sliced((1, 2, 3, 4, 5, 6, 7, 8), 3))
    [(1, 2, 3), (4, 5, 6), (7, 8)]

    If the length of *seq* is not divisible by *n* and *strict* is
    ``True``, then ``ValueError`` will be raised before the last
    slice is yielded.

    This function will only work for iterables that support slicing.
    For non-sliceable iterables, see :func:`chunked`.

    """
    iterator = takewhile(len, (seq[i : i + n] for i in count(0, n)))
    if strict:

        def ret():
            for _slice in iterator:
                if len(_slice) != n:
                    raise ValueError("seq is not divisible by n.")
                yield _slice

        return ret()
    else:
        return iterator

def decorator(*wrapping_args, **wrapping_kwargs):
    def outer_wrapper(f):
        def inner_wrapper(*args, **kwargs):
            result = f(*args, **kwargs)
            wrapping_args_ = list(wrapping_args)
            wrapping_args_.insert(result_index, result)
            return wrapping_func(*wrapping_args_, **wrapping_kwargs)

        return inner_wrapper

    return outer_wrapper

def peek(self, default=_marker):
    """Return the item that will be next returned from ``next()``.

    Return ``default`` if there are no items left. If ``default`` is not
    provided, raise ``StopIteration``.

    """
    if not self._cache:
        try:
            self._cache.append(next(self._it))
        except StopIteration:
            if default is _marker:
                raise
            return default
    return self._cache[0]

def random_derangement(iterable):
    """Return a random derangement of elements in the iterable.

    Equivalent to but much faster than ``choice(list(derangements(iterable)))``.

    """
    seq = tuple(iterable)
    if len(seq) < 2:
        if len(seq) == 0:
            return ()
        raise IndexError('No derangments to choose from')
    perm = list(range(len(seq)))
    start = tuple(perm)
    while True:
        shuffle(perm)
        if not any(map(is_, start, perm)):
            return itemgetter(*perm)(seq)

def _extract_buffered(iterator, index_and_position):
    'Arbitrary index order, greedily consumed'
    buffer = {}
    iterator_position = -1
    next_to_emit = 0

    for index, order in index_and_position:
        advance = index - iterator_position
        if advance:
            try:
                value = next(islice(iterator, advance - 1, None))
            except StopIteration:
                raise IndexError(index) from None
            iterator_position = index

        buffer[order] = value

        while next_to_emit in buffer:
            yield buffer.pop(next_to_emit)
            next_to_emit += 1

def count_cycle(iterable, n=None):
    """Cycle through the items from *iterable* up to *n* times, yielding
    the number of completed cycles along with each item. If *n* is omitted the
    process repeats indefinitely.

    >>> list(count_cycle('AB', 3))
    [(0, 'A'), (0, 'B'), (1, 'A'), (1, 'B'), (2, 'A'), (2, 'B')]

    """
    if n is not None:
        return product(range(n), iterable)
    seq = tuple(iterable)
    if not seq:
        return iter(())
    counter = count() if n is None else range(n)
    return zip(repeat_each(counter, len(seq)), cycle(seq))

