def index(self, value):
    if self._growing:
        if self._start <= value < self._stop:
            q, r = divmod(value - self._start, self._step)
            if r == self._zero:
                return int(q)
    else:
        if self._start >= value > self._stop:
            q, r = divmod(self._start - value, -self._step)
            if r == self._zero:
                return int(q)

    raise ValueError(f"{value} is not in numeric range")

def set_partitions_helper(L, k):
    n = len(L)
    if k == 1:
        yield [L]
    elif n == k:
        yield [[s] for s in L]
    else:
        e, *M = L
        for p in set_partitions_helper(M, k - 1):
            yield [[e], *p]
        for p in set_partitions_helper(M, k):
            for i in range(len(p)):
                yield p[:i] + [[e] + p[i]] + p[i + 1 :]

def _extract_monotonic(iterator, indices):
    'Non-decreasing indices, lazily consumed'
    num_read = 0
    for index in indices:
        advance = index - num_read
        try:
            value = next(islice(iterator, advance, None))
        except ValueError:
            if advance != -1 or index < 0:
                raise ValueError(f'Invalid index: {index}') from None
        except StopIteration:
            raise IndexError(index) from None
        else:
            num_read += advance + 1
        yield value

def _get_slice(self, index):
    # Normalize the slice's arguments
    step = 1 if (index.step is None) else index.step
    if step > 0:
        start = 0 if (index.start is None) else index.start
        stop = maxsize if (index.stop is None) else index.stop
    elif step < 0:
        start = -1 if (index.start is None) else index.start
        stop = (-maxsize - 1) if (index.stop is None) else index.stop
    else:
        raise ValueError('slice step cannot be zero')

    # If either the start or stop index is negative, we'll need to cache
    # the rest of the iterable in order to slice from the right side.
    if (start < 0) or (stop < 0):
        self._cache.extend(self._it)
    # Otherwise we'll need to find the rightmost index and cache to that
    # point.
    else:
        n = min(max(start, stop) + 1, maxsize)
        cache_len = len(self._cache)
        if n >= cache_len:
            self._cache.extend(islice(self._it, n - cache_len))

    return list(self._cache)[index]

def _reader(self):
    q = Queue()

    def callback(*args, **kwargs):
        if self._aborted:
            raise AbortThread('canceled by user')

        q.put((args, kwargs))

    self._future = self._executor.submit(
        self._func, **{self._callback_kwd: callback}
    )

    while True:
        try:
            item = q.get(timeout=self._wait_seconds)
        except Empty:
            pass
        else:
            q.task_done()
            yield item

        if self._future.done():
            break

    remaining = []
    while True:
        try:
            item = q.get_nowait()
        except Empty:
            break
        else:
            q.task_done()
            remaining.append(item)
    q.join()
    yield from remaining
